{
  "template": {
    "format_id": "amvision.workflow-graph-template.v1",
    "template_id": "{{templateId}}",
    "template_version": "{{templateVersion}}",
    "display_name": "YOLOX Deployment Detection Lifecycle Real Path",
    "description": "控制一个已有 sync deployment 资源，并在 backend-service 当前 deployment control plane 上按顺序执行 start、warmup、detection、health、stop。",
    "nodes": [
      {
        "node_id": "start",
        "node_type_id": "core.service.yolox-deployment.start",
        "parameters": {
          "deployment_instance_id": "{{deploymentInstanceId}}",
          "runtime_mode": "sync"
        },
        "metadata": {
          "sequence_index": 1
        }
      },
      {
        "node_id": "warmup",
        "node_type_id": "core.service.yolox-deployment.warmup",
        "parameters": {
          "deployment_instance_id": "{{deploymentInstanceId}}",
          "runtime_mode": "sync"
        },
        "metadata": {
          "sequence_index": 2
        }
      },
      {
        "node_id": "detect",
        "node_type_id": "core.model.yolox-detection",
        "parameters": {
          "deployment_instance_id": "{{deploymentInstanceId}}",
          "auto_start_process": false,
          "score_threshold": 0.3,
          "save_result_image": false,
          "return_preview_image_base64": false
        },
        "metadata": {
          "sequence_index": 3
        }
      },
      {
        "node_id": "health",
        "node_type_id": "core.service.yolox-deployment.health",
        "parameters": {
          "deployment_instance_id": "{{deploymentInstanceId}}",
          "runtime_mode": "sync"
        },
        "metadata": {
          "sequence_index": 4
        }
      },
      {
        "node_id": "stop",
        "node_type_id": "core.service.yolox-deployment.stop",
        "parameters": {
          "deployment_instance_id": "{{deploymentInstanceId}}",
          "runtime_mode": "sync"
        },
        "metadata": {
          "sequence_index": 5
        }
      }
    ],
    "edges": [],
    "template_inputs": [
      {
        "input_id": "request_image",
        "display_name": "Request Image",
        "payload_type_id": "image-ref.v1",
        "target_node_id": "detect",
        "target_port": "image"
      }
    ],
    "template_outputs": [
      {
        "output_id": "start_body",
        "display_name": "Start Body",
        "payload_type_id": "response-body.v1",
        "source_node_id": "start",
        "source_port": "body"
      },
      {
        "output_id": "warmup_body",
        "display_name": "Warmup Body",
        "payload_type_id": "response-body.v1",
        "source_node_id": "warmup",
        "source_port": "body"
      },
      {
        "output_id": "detections",
        "display_name": "Detections",
        "payload_type_id": "detections.v1",
        "source_node_id": "detect",
        "source_port": "detections"
      },
      {
        "output_id": "health_body",
        "display_name": "Health Body",
        "payload_type_id": "response-body.v1",
        "source_node_id": "health",
        "source_port": "body"
      },
      {
        "output_id": "stop_body",
        "display_name": "Stop Body",
        "payload_type_id": "response-body.v1",
        "source_node_id": "stop",
        "source_port": "body"
      }
    ],
    "metadata": {
      "intended_saved_object_key": "workflows/projects/{{projectId}}/templates/{{templateId}}/versions/{{templateVersion}}/template.json",
      "example_kind": "deployment-control-detection-lifecycle-real-path",
      "deployment_instance_id_placeholder": "replace-with-existing-deployment-instance-id",
      "uses_existing_deployment_instance": true,
      "deployment_runtime_owner": "backend-service",
      "node_groups": {
        "deployment_control": ["start", "warmup", "health", "stop"],
        "model_node": ["detect"]
      },
      "execution_order_note": "当前最小执行器会按 nodes 声明顺序稳定执行零入度节点，因此该示例通过节点声明顺序表达 start -> warmup -> detection -> health -> stop。"
    }
  }
}

{
  "application": {
    "format_id": "amvision.flow-application.v1",
    "application_id": "{{applicationId}}",
    "display_name": "YOLOX Deployment Detection Lifecycle Real Path App",
    "template_ref": {
      "template_id": "{{templateId}}",
      "template_version": "{{templateVersion}}",
      "source_kind": "json-file",
      "source_uri": "workflows/projects/{{projectId}}/templates/{{templateId}}/versions/{{templateVersion}}/template.json",
      "metadata": {}
    },
    "runtime_mode": "python-json-workflow",
    "description": "面向 Postman 手工调试的最小 FlowApplication 示例，控制并使用一个已有 deployment 资源，使用真实 workflow object key 路径。",
    "bindings": [
      {
        "binding_id": "request_image",
        "direction": "input",
        "template_port_id": "request_image",
        "binding_kind": "workflow-execute-input",
        "config": {
          "payload_type_id": "image-ref.v1",
          "content_type": "image/*"
        },
        "metadata": {}
      },
      {
        "binding_id": "start_body",
        "direction": "output",
        "template_port_id": "start_body",
        "binding_kind": "workflow-execute-output",
        "config": {
          "payload_type_id": "response-body.v1"
        },
        "metadata": {}
      },
      {
        "binding_id": "warmup_body",
        "direction": "output",
        "template_port_id": "warmup_body",
        "binding_kind": "workflow-execute-output",
        "config": {
          "payload_type_id": "response-body.v1"
        },
        "metadata": {}
      },
      {
        "binding_id": "detections",
        "direction": "output",
        "template_port_id": "detections",
        "binding_kind": "workflow-execute-output",
        "config": {
          "payload_type_id": "detections.v1"
        },
        "metadata": {}
      },
      {
        "binding_id": "health_body",
        "direction": "output",
        "template_port_id": "health_body",
        "binding_kind": "workflow-execute-output",
        "config": {
          "payload_type_id": "response-body.v1"
        },
        "metadata": {}
      },
      {
        "binding_id": "stop_body",
        "direction": "output",
        "template_port_id": "stop_body",
        "binding_kind": "workflow-execute-output",
        "config": {
          "payload_type_id": "response-body.v1"
        },
        "metadata": {}
      }
    ],
    "metadata": {
      "intended_saved_object_key": "workflows/projects/{{projectId}}/applications/{{applicationId}}/application.json",
      "example_kind": "deployment-control-detection-lifecycle-real-path",
      "uses_existing_deployment_instance": true,
      "deployment_instance_id_placeholder": "replace-with-existing-deployment-instance-id"
    }
  }
}
